function StepIndicator({ current, total }: { current: number; total: number }) {
  return (
    <div style={{ display: 'flex', gap: 8, marginBottom: 24 }}>
      {Array.from({ length: total }, (_, i) => (
        <div key={i} style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{
            width: 32, height: 32, borderRadius: '50%',
            display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 600, fontSize: 14,
            backgroundColor: i <= current ? '#6366f1' : '#e5e7eb',
            color: i <= current ? 'white' : '#9ca3af',
          }}>
            {i < current ? '\u2713' : i + 1}
          </div>
          {i < total - 1 && <div style={{ width: 40, height: 2, backgroundColor: i < current ? '#6366f1' : '#e5e7eb' }} />}
        </div>
      ))}
    </div>
  );
}

export default function MultiStepForm() {
