            style={{ width: '100%', padding: 10, marginBottom: 16, borderRadius: 6, border: '1px solid #d1d5db' }} />
        </div>
      )}

      {step === 1 && (
        <div>
          <h3>{steps[1]}</h3>
          <input type="email" placeholder="Email" value={data.email} onChange={e => update({ email: e.target.value })}
