      {step === 2 && (
        <div>
          <h3>{steps[2]}</h3>
          <label style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 16, cursor: 'pointer' }}>
            <input type="checkbox" checked={data.newsletter} onChange={e => update({ newsletter: e.target.checked })} />
