                }}>
                {plan.charAt(0).toUpperCase() + plan.slice(1)}
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Navigation */}
      <div style={{ display: 'flex', justifyContent: 'space-between', marginTop: 24 }}>
        <button onClick={() => setStep(s => s - 1)} disabled={step === 0}
          style={{ padding: '10px 20px', borderRadius: 6, border: '1px solid #d1d5db', cursor: 'pointer' }}>Back</button>
        {step < steps.length - 1 ? (
          <button onClick={() => setStep(s => s + 1)}
            style={{ padding: '10px 20px', borderRadius: 6, backgroundColor: '#6366f1', color: 'white', border: 'none', cursor: 'pointer' }}>Next</button>
        ) : (
          <button onClick={() => alert(JSON.stringify(data, null, 2))}
            style={{ padding: '10px 20px', borderRadius: 6, backgroundColor: '#10b981', color: 'white', border: 'none', cursor: 'pointer' }}>Submit</button>
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';

function useDebouncedValue<T>(value: T, delay: number): T {
  const [debounced, setDebounced] = useState(value);
  useEffect(() => {
    const timer = setTimeout(() => setDebounced(value), delay);
    return () => clearTimeout(timer);
  }, [value, delay]);
  return debounced;
}

function UsernameField() {
  const [username, setUsername] = useState('');
  const [status, setStatus] = useState<'idle' | 'checking' | 'available' | 'taken'>('idle');
  const debouncedUsername = useDebouncedValue(username, 500);

  useEffect(() => {
    if (!debouncedUsername) { setStatus('idle'); return; }
    setStatus('checking');
    // Simulated API call
    const timer = setTimeout(() => {
      const taken = ['admin', 'user', 'test'].includes(debouncedUsername.toLowerCase());
      setStatus(taken ? 'taken' : 'available');
    }, 300);
    return () => clearTimeout(timer);
  }, [debouncedUsername]);

  return (
    <div>
      <input value={username} onChange={e => setUsername(e.target.value)} placeholder="Choose a username" />
      {status === 'checking' && <span>Checking...</span>}
      {status === 'available' && <span style={{ color: 'green' }}>\u2713 Available</span>}
      {status === 'taken' && <span style={{ color: 'red' }}>\u2717 Already taken</span>}
    </div>
  );
}
